import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.CuteRReP.js";const u=JSON.parse('{"title":"cm-skill-chain","description":"Skill Chain Engine — compose skills into automated pipelines. One task triggers multi-skill workflows with progress tracking, auto-detection, and step managemen","frontmatter":{"title":"cm-skill-chain","description":"Skill Chain Engine — compose skills into automated pipelines. One task triggers multi-skill workflows with progress tracking, auto-detection, and step managemen","keywords":["cm-skill-chain","cody master","ai skill"],"robots":"index, follow"},"headers":[],"relativePath":"skills/cm-skill-chain.md","filePath":"skills/cm-skill-chain.md"}'),n={name:"skills/cm-skill-chain.md"};function s(c,e,r,l,d,h){return a(),o("div",null,[...e[0]||(e[0]=[i(`<blockquote><p><strong>📋 Full Skill Source</strong> — This is the complete, unedited SKILL.md file. Nothing is hidden or summarized.</p></blockquote><p><a href="./">← Back to Skills Library</a></p><h1 id="skill-chain-engine" tabindex="-1">Skill Chain Engine <a class="header-anchor" href="#skill-chain-engine" aria-label="Permalink to &quot;Skill Chain Engine&quot;">​</a></h1><blockquote><p><strong>TRIZ #40 Composite Materials</strong> — Skills compose into pipelines. One command → full workflow → automated step progression.</p></blockquote><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><p>ALWAYS trigger for: chain, pipeline, workflow, multi-step, end-to-end, &quot;run the whole thing&quot;, &quot;full process&quot;, &quot;feature pipeline&quot;, &quot;bug fix flow&quot;, &quot;from scratch to deploy&quot;, &quot;brainstorm to ship&quot;, &quot;chuỗi skill&quot;, &quot;pipeline đầy đủ&quot;</p><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>cody chain list</code></td><td>Show all available chains</td></tr><tr><td><code>cody chain info &amp;lt;id&amp;gt;</code></td><td>Show chain pipeline details</td></tr><tr><td><code>cody chain auto &quot;task&quot;</code></td><td>Auto-detect best chain &amp; start</td></tr><tr><td><code>cody chain start &amp;lt;id&amp;gt; &quot;task&quot;</code></td><td>Start specific chain</td></tr><tr><td><code>cody chain status [exec-id]</code></td><td>Show progress</td></tr><tr><td><code>cody chain advance &amp;lt;exec-id&amp;gt;</code></td><td>Complete current step, move to next</td></tr><tr><td><code>cody chain skip &amp;lt;exec-id&amp;gt;</code></td><td>Skip current step</td></tr><tr><td><code>cody chain abort &amp;lt;exec-id&amp;gt;</code></td><td>Cancel chain</td></tr><tr><td><code>cody chain history</code></td><td>View past chain runs</td></tr></tbody></table><h2 id="naming-convention" tabindex="-1">Naming Convention <a class="header-anchor" href="#naming-convention" aria-label="Permalink to &quot;Naming Convention&quot;">​</a></h2><p>Step names use short-form identifiers — the <code>cm-</code> prefix is stripped by convention. Full skill names: <code>cm-brainstorm-idea</code>, <code>cm-planning</code>, <code>cm-tdd</code>, <code>cm-execution</code>, <code>cm-quality-gate</code>, <code>cm-safe-deploy</code>, <code>cm-debugging</code>, <code>cm-content-factory</code>, <code>cm-ads-tracker</code>, <code>cm-project-bootstrap</code>, <code>cm-code-review</code>. Exception: <code>cro-methodology</code> has no <code>cm-</code> prefix.</p><h2 id="built-in-chains" tabindex="-1">Built-in Chains <a class="header-anchor" href="#built-in-chains" aria-label="Permalink to &quot;Built-in Chains&quot;">​</a></h2><h3 id="🚀-feature-development-6-steps" tabindex="-1">🚀 feature-development (6 steps) <a class="header-anchor" href="#🚀-feature-development-6-steps" aria-label="Permalink to &quot;🚀 feature-development (6 steps)&quot;">​</a></h3><p><code>brainstorm-idea → planning → tdd → execution → quality-gate → safe-deploy</code></p><h3 id="🐛-bug-fix-3-steps" tabindex="-1">🐛 bug-fix (3 steps) <a class="header-anchor" href="#🐛-bug-fix-3-steps" aria-label="Permalink to &quot;🐛 bug-fix (3 steps)&quot;">​</a></h3><p><code>debugging → tdd → quality-gate</code></p><h3 id="📝-content-launch-3-steps" tabindex="-1">📝 content-launch (3 steps) <a class="header-anchor" href="#📝-content-launch-3-steps" aria-label="Permalink to &quot;📝 content-launch (3 steps)&quot;">​</a></h3><p><code>content-factory → ads-tracker → cro-methodology</code></p><h3 id="🏗️-new-project-6-steps" tabindex="-1">🏗️ new-project (6 steps) <a class="header-anchor" href="#🏗️-new-project-6-steps" aria-label="Permalink to &quot;🏗️ new-project (6 steps)&quot;">​</a></h3><p><code>project-bootstrap → planning → tdd → execution → quality-gate → safe-deploy</code></p><h3 id="🔍-cm-code-review-3-steps" tabindex="-1">🔍 cm-code-review (3 steps) <a class="header-anchor" href="#🔍-cm-code-review-3-steps" aria-label="Permalink to &quot;🔍 cm-code-review (3 steps)&quot;">​</a></h3><p><code>cm-code-review → quality-gate → safe-deploy</code></p><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><ol><li><strong>Start</strong>: Use <code>chain auto</code> for auto-detection or <code>chain start</code> for specific chains</li><li><strong>Execute</strong>: Work through each skill step, using <code>@[/skill-name]</code> to invoke</li><li><strong>Advance</strong>: When step is done, run <code>chain advance &amp;lt;id&amp;gt; &quot;summary&quot;</code></li><li><strong>Repeat</strong>: Continue until all steps complete</li><li><strong>Track</strong>: Use <code>chain status</code> to monitor progress anytime</li></ol><h2 id="integration-with-other-skills" tabindex="-1">Integration with Other Skills <a class="header-anchor" href="#integration-with-other-skills" aria-label="Permalink to &quot;Integration with Other Skills&quot;">​</a></h2><ul><li><strong>cm-judge</strong>: Automatically suggests <code>CHAIN_NEXT</code> action for chain-linked tasks</li><li><strong>cm-continuity</strong>: Chain progress persists across sessions via kanban data</li><li><strong>Dashboard API</strong>: Full REST API at <code>/api/chains</code> and <code>/api/chain-executions</code></li></ul><h2 id="for-ai-agents" tabindex="-1">For AI Agents <a class="header-anchor" href="#for-ai-agents" aria-label="Permalink to &quot;For AI Agents&quot;">​</a></h2><p>When dispatching tasks that match a chain pattern:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Check if task matches a chain: suggestChain(taskTitle)</span></span>
<span class="line"><span>2. If match found, suggest to user: &quot;This task matches the X chain pipeline&quot;</span></span>
<span class="line"><span>3. If user agrees, start the chain and invoke skills in order</span></span>
<span class="line"><span>4. After completing each skill, advance the chain</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div>`,28)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
